GameReward = {}

function GameReward:sendNotificationResult(player, reward)
    if reward and reward.IsNotification and #reward.NotificationContent ~= 0 then
        local data = {
            message = reward.NotificationContent,
            top = true
        }
        if #reward.NotificationParams ~= 0 then
            data.params = player:getDisplayName() .. "#" .. reward.NotificationParams
        else
            data.params = player:getDisplayName()
        end
        WebService:SendMsg(nil, json.encode(data), 4, "game", GameMatch.gameType)
    end
    return reward.Id
end

function GameReward:onPlayerGetReward(player, reward)
    if not reward then
        return false
    end
    local hasGet = true
    if reward.RewardType == Define.RewardType.Exp then
        self:onPlayerAddExp(player, reward.Count)
    elseif reward.RewardType == Define.RewardType.Money then
        player.Wallet:addMoney(reward.RewardId or 0, reward.Count or 0)
    elseif reward.RewardType == Define.RewardType.Tower then
        player:addNewTower(reward.RewardId)
    elseif reward.RewardType == Define.RewardType.Skin then
        player:onGetNewSkin(reward.RewardId)
    elseif reward.RewardType == Define.RewardType.PayItem then
        local config = PayStoreConfig:getConfigById(reward.RewardId)
        if config.itemType == Define.PayStoreItem.ShortcutBarOne or config.itemType == Define.PayStoreItem.ShortcutBarTwo then
            player.payItemList[tostring(config.itemType)] = config.itemType
        end
        GamePacketSender:sendPayItemList(player.rakssid, player.payItemList)
    end

    if not hasGet then
        local redress_reward = RewardConfig:getRewardById(reward.RedressRewardId)
        if redress_reward then
            return self:onPlayerGetReward(player, redress_reward)
        else
            print("Do not have Redress Reward by Id(" .. reward.RedressRewardId .. ")")
        end
        return
    end
    self:sendNotificationResult(player, reward)
    return reward.Id
end

function GameReward:onPlayerAddExp(player, count)
    player:addExp(count)
end

return GameReward